const item = $input.first().json;
const body = item.body;
const errors = [];

if (!body || !Array.isArray(body.ingredients) || body.ingredients.length === 0) {
  errors.push('ingredients: Mindestens eine Zutat erforderlich');
}
if (!body || !body.portions || isNaN(Number(body.portions)) || Number(body.portions) < 1) {
  errors.push('portions: Gültige Zahl >= 1 erforderlich');
}
if (!body || !body.chefs || isNaN(Number(body.chefs)) || Number(body.chefs) < 1) {
  errors.push('chefs: Gültige Zahl >= 1 erforderlich');
}
const validCuisines = ['german', 'italian', 'japanese', 'indian', 'gourmet', 'fusion'];
if (!body || !body.cuisine || !validCuisines.includes(body.cuisine)) {
  errors.push('cuisine: Muss einer von ' + validCuisines.join(', ') + ' sein');
}
if (!body || !body.complexity) {
  errors.push('complexity: Pflichtfeld fehlt');
}

if (errors.length > 0) {
  return [{ json: { valid: false, errors } }];
}

return [{ json: { ...item, valid: true } }];

// IP-basiertes Rate Limiting via Static Data
const staticData = $getWorkflowStaticData('global');
const ip = ($input.first().json.headers || {})['x-forwarded-for'] || 'unknown';
const now = Date.now();
const windowMs = 24 * 60 * 60 * 1000; // 24 Stunden
const maxRequests = 50; // Max Anfragen pro IP pro Tag

if (!staticData.ipLog) staticData.ipLog = {};

// Alte Einträge bereinigen
for (const key of Object.keys(staticData.ipLog)) {
  if (now - staticData.ipLog[key].start > windowMs) {
    delete staticData.ipLog[key];
  }
}

if (!staticData.ipLog[ip]) {
  staticData.ipLog[ip] = { count: 1, start: now };
} else if (staticData.ipLog[ip].count >= maxRequests) {
  const retryAfterHours = Math.ceil((staticData.ipLog[ip].start + windowMs - now) / 3600000);
  return [{ json: { rateLimitOk: false, retryAfterHours } }];
} else {
  staticData.ipLog[ip].count++;
}

return [{ json: { ...($input.first().json), rateLimitOk: true } }];

