try {
  const text = $input.first().json.output[0].content[0].text;
  const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(clean);

  if (!parsed.recipes || !Array.isArray(parsed.recipes)) {
    return [{ json: { parseSuccess: false, error: 'Antwort enthält kein gültiges recipes-Array' } }];
  }

  return [{ json: { ...parsed, parseSuccess: true } }];
} catch (error) {
  return [{ json: { parseSuccess: false, error: error.message } }];
}
